def _resolve_page_range(spec: str | None, total: int) -> list[int] | None:
    if not spec:
        return None

    pages = set()
    for part in spec.split(","):
        token = part.strip()
        if not token:
            continue
        if "-" in token:
            start_raw, end_raw = token.split("-", 1)
            start = int(start_raw)
            end = int(end_raw)
            if start > end:
                start, end = end, start
            pages.update(range(start, end + 1))
        else:
            pages.add(int(token))

    normalized = sorted(p for p in pages if 1 <= p <= total)
    if not normalized:
        raise ValueError("Page selection is outside the PDF page range")
    return normalized


def _save_upload_file(upload: UploadFile, destination: Path) -> None:
    total = 0
    with destination.open("wb") as handle:
        while True:
            chunk = upload.file.read(1024 * 1024)
            if not chunk:
                break
            total += len(chunk)
            if total > MAX_UPLOAD_BYTES:
                raise HTTPException(status_code=413, detail="PDF exceeds 50MB upload limit")
            handle.write(chunk)

    if total == 0:
        raise HTTPException(status_code=400, detail="Uploaded PDF file is empty")


def _has_pdf_signature(file_path: Path) -> bool:
    with file_path.open("rb") as handle:
        return handle.read(5) == b"%PDF-"


def _append_log(job_id: str, message: str) -> None:
    with _jobs_lock:
        job = _jobs.get(job_id)
        if job is None:
            return
        job.logs.append(message)
        if len(job.logs) > 300:
            job.logs = job.logs[-300:]
        job.updated_at = time.time()


def _update_job(job_id: str, **updates: Any) -> None:
    with _jobs_lock:
        job = _jobs.get(job_id)
        if job is None:
            return
        for key, value in updates.items():
            setattr(job, key, value)
        job.updated_at = time.time()


def _job_snapshot(job: JobState) -> dict[str, Any]:
    return {
        "jobId": job.job_id,
        "sourceFileName": job.source_file_name,
        "status": job.status,
        "phase": job.phase,
        "progress": job.progress,
        "message": job.message,
        "logs": list(job.logs),
        "stats": dict(job.stats),
        "output": {
            "markdownFileName": job.output_file_name,
            "markdownDownloadUrl": (
                f"/api/jobs/{job.job_id}/markdown" if job.output_path else None
            ),
            "pdfDownloadUrl": f"/api/jobs/{job.job_id}/pdf",
            "pageImagesUrl": (
                f"/api/jobs/{job.job_id}/page-images" if job.status == "completed" else None
            ),
        },
        "selectedPageNumbers": list(job.selected_page_numbers),
        "error": job.error,
        "createdAt": job.created_at,
        "updatedAt": job.updated_at,
    }


def _preview_image_path(job_id: str, page_number: int) -> Path:
    preview_dir = Path(config.OUTPUT_DIR) / "jobs" / job_id / "preview"
    preview_dir.mkdir(parents=True, exist_ok=True)
    return preview_dir / f"page_{page_number:04d}.jpg"


def _render_preview_page(source_pdf_path: str, page_number: int, output_path: Path, dpi: int = 140) -> None:
    doc = fitz.open(source_pdf_path)
    try:
        page = doc[page_number - 1]
        scale = dpi / 72.0
        mat = fitz.Matrix(scale, scale)
        pix = page.get_pixmap(matrix=mat, alpha=False)
        pix.save(str(output_path), jpg_quality=88)
    finally:
        doc.close()


def _run_parse_job(
    job_id: str,
    pdf_path: str,
    source_file_name: str,
    api_key: str | None,
    dpi: int | None,
    model: str | None,
    pages_spec: str | None,
) -> None:
    original_api_key = config.GROQ_API_KEY
    original_dpi = config.RASTERIZE_DPI
    original_model = config.VLM_MODEL

    try:
        _update_job(
            job_id,
            status="running",
            phase="analyzing",
            progress=5,
            message="Analyzing PDF structure",
        )
        _append_log(job_id, "Starting document analysis")

        if api_key and api_key.strip():
            set_api_key(api_key)
            _append_log(job_id, "Using API key from UI settings")

        if dpi is not None:
            config.RASTERIZE_DPI = dpi
            _append_log(job_id, f"Rasterization DPI set to {dpi}")

        if model is not None and model.strip():
            config.VLM_MODEL = model.strip()
            _append_log(job_id, f"Vision model set to {config.VLM_MODEL}")

        if not config.GROQ_API_KEY:
            raise RuntimeError("GROQ API key not configured. Set it in .env or UI Settings.")

        analyzed_pages = analyze_pdf(pdf_path, verbose=False)
        selected_pages = analyzed_pages
        if pages_spec and pages_spec.strip():
            selected_numbers = _resolve_page_range(pages_spec, len(analyzed_pages))
            if selected_numbers:
                selected_pages = [p for p in analyzed_pages if p.page_number in selected_numbers]
                _append_log(job_id, f"Filtered pages: {pages_spec}")

        selected_page_numbers = [p.page_number for p in selected_pages]
        _update_job(job_id, selected_page_numbers=selected_page_numbers)

        stats = {
            "totalPages": len(selected_pages),
            "textPages": sum(1 for page in selected_pages if page.page_type == PageType.TEXT),
            "imagePages": sum(1 for page in selected_pages if page.page_type == PageType.IMAGE),
            "mixedPages": sum(1 for page in selected_pages if page.page_type == PageType.MIXED),
        }
        _update_job(job_id, progress=20, stats=stats, message="Analysis complete")
        _append_log(job_id, f"Pages selected: {stats['totalPages']}")

        _update_job(job_id, phase="processing", progress=25, message="Processing pages")
        _append_log(job_id, "Processing pages with VLM pipeline")

        def _progress_callback(done: int, total: int, page_info: Any) -> None:
            base = 25
            span = 60
            progress = base + int((done / max(total, 1)) * span)
            _update_job(job_id, progress=progress, message=f"Processed page {page_info.page_number}")
            _append_log(job_id, f"Page {page_info.page_number}: {page_info.page_type.value}")

        with tempfile.TemporaryDirectory(prefix=f"pdf_parser_{job_id}_") as tmp_dir:
            processed_pages = process_all_pages(
                pdf_path=pdf_path,
                pages=selected_pages,
                tmp_dir=tmp_dir,
                verbose=False,
                progress_callback=_progress_callback,
            )

        _update_job(job_id, phase="building_markdown", progress=90, message="Building markdown")
        _append_log(job_id, "Compiling markdown output")

        output_dir = Path(config.OUTPUT_DIR) / "jobs" / job_id
        output_dir.mkdir(parents=True, exist_ok=True)
        output_path = output_dir / f"{Path(source_file_name).stem}_knowledge.md"

        final_path = build_knowledge_base(
            pages=processed_pages,
            pdf_path=pdf_path,
            output_path=str(output_path),
        )

        _update_job(
            job_id,
            status="completed",
            phase="completed",
            progress=100,
            message="Parsing completed",
            output_path=final_path,
            output_file_name=Path(final_path).name,
        )
        _append_log(job_id, "Job completed successfully")

    except Exception as exc:
        _update_job(
            job_id,
            status="failed",
            phase="failed",
            progress=100,
            message="Parsing failed",
            error=f"{type(exc).__name__}: {exc}",
        )
        _append_log(job_id, f"Error: {type(exc).__name__}: {exc}")
        _append_log(job_id, traceback.format_exc())
    finally:
        # The parser currently uses global config. Restore process defaults after each job.
        config.RASTERIZE_DPI = original_dpi
        config.VLM_MODEL = original_model
        if config.GROQ_API_KEY != original_api_key:
            set_api_key(original_api_key)


