@app.post("/api/jobs", status_code=202)
async def create_job(
    file: UploadFile = File(...),
    apiKey: str | None = Form(default=None),
    dpi: int | None = Form(default=None),
    model: str | None = Form(default=None),
    pages: str | None = Form(default=None),
) -> dict[str, Any]:
    file_name = file.filename or "document.pdf"
    if not file_name.lower().endswith(".pdf"):
        raise HTTPException(status_code=400, detail="Only PDF files are supported")

    job_id = uuid.uuid4().hex
    job_dir = Path(config.OUTPUT_DIR) / "jobs" / job_id
    job_dir.mkdir(parents=True, exist_ok=True)

    pdf_path = job_dir / "input.pdf"
    _save_upload_file(file, pdf_path)
    if not _has_pdf_signature(pdf_path):
        raise HTTPException(status_code=400, detail="Uploaded file is not a valid PDF")

    job = JobState(
        job_id=job_id,
        source_file_name=file_name,
        source_pdf_path=str(pdf_path),
        message="Upload complete, waiting for worker",
    )
    with _jobs_lock:
        _jobs[job_id] = job

    _executor.submit(
        _run_parse_job,
        job_id,
        str(pdf_path),
        file_name,
        apiKey,
        dpi,
        model,
        pages,
    )

    return _job_snapshot(job)


@app.get("/api/jobs/{job_id}")
def get_job(job_id: str) -> dict[str, Any]:
    with _jobs_lock:
        job = _jobs.get(job_id)
        if job is None:
            raise HTTPException(status_code=404, detail="Job not found")
        return _job_snapshot(job)


@app.get("/api/jobs/{job_id}/result")
def get_job_result(job_id: str) -> dict[str, Any]:
    with _jobs_lock:
        job = _jobs.get(job_id)
        if job is None:
            raise HTTPException(status_code=404, detail="Job not found")
        if job.status != "completed" or not job.output_path:
            raise HTTPException(status_code=409, detail="Job has not completed")
        output_path = Path(job.output_path)
        source_name = job.source_file_name
        markdown_file_name = job.output_file_name or output_path.name
        selected_page_numbers = list(job.selected_page_numbers)

    if not output_path.exists():
        raise HTTPException(status_code=404, detail="Output file is missing")

    markdown = output_path.read_text(encoding="utf-8", errors="replace")
    return {
        "jobId": job_id,
        "sourceFileName": source_name,
        "markdownFileName": markdown_file_name,
        "markdown": markdown,
        "selectedPageNumbers": selected_page_numbers,
    }


