@app.get("/api/jobs/{job_id}/page-images")
def list_page_images(job_id: str) -> dict[str, Any]:
    with _jobs_lock:
        job = _jobs.get(job_id)
        if job is None:
            raise HTTPException(status_code=404, detail="Job not found")
        if job.status != "completed":
            raise HTTPException(status_code=409, detail="Job has not completed")
        page_numbers = list(job.selected_page_numbers)

    images = [
        {
            "pageNumber": page_number,
            "imageUrl": f"/api/jobs/{job_id}/pages/{page_number}/image",
        }
        for page_number in page_numbers
    ]
    return {
        "jobId": job_id,
        "pages": images,
    }


@app.get("/api/jobs/{job_id}/pages/{page_number}/image")
def get_page_image(job_id: str, page_number: int) -> FileResponse:
    with _jobs_lock:
        job = _jobs.get(job_id)
        if job is None:
            raise HTTPException(status_code=404, detail="Job not found")
        if job.status != "completed":
            raise HTTPException(status_code=409, detail="Job has not completed")
        selected_pages = set(job.selected_page_numbers)
        source_pdf_path = Path(job.source_pdf_path)

    if page_number not in selected_pages:
        raise HTTPException(status_code=404, detail="Page image is not available for this job")
    if not source_pdf_path.exists():
        raise HTTPException(status_code=404, detail="Source PDF is missing")

    preview_path = _preview_image_path(job_id, page_number)
    if not preview_path.exists():
        _render_preview_page(str(source_pdf_path), page_number, preview_path)

    return FileResponse(
        path=str(preview_path),
        media_type="image/jpeg",
        filename=preview_path.name,
    )


@app.get("/", include_in_schema=False)
def serve_ui_root() -> Any:
    if UI_INDEX_FILE.exists():
        return FileResponse(path=str(UI_INDEX_FILE), media_type="text/html")
    return {"status": "ok", "message": "UI build not found. Build ui/ first."}


@app.get("/{full_path:path}", include_in_schema=False)
def serve_ui_spa(full_path: str) -> FileResponse:
    if full_path.startswith("api/"):
        raise HTTPException(status_code=404, detail="Not found")

    candidate = UI_DIST_DIR / full_path
    if candidate.exists() and candidate.is_file():
        return FileResponse(path=str(candidate))

    if UI_INDEX_FILE.exists():
        return FileResponse(path=str(UI_INDEX_FILE), media_type="text/html")

    raise HTTPException(status_code=404, detail="UI build not found")


@app.get("/", include_in_schema=False)
def serve_frontend_root() -> FileResponse:
    index_path = FRONTEND_DIST / "index.html"
    if not index_path.exists():
        raise HTTPException(status_code=404, detail="Frontend build not found")
    return FileResponse(path=str(index_path), media_type="text/html")


@app.get("/{full_path:path}", include_in_schema=False)
def serve_frontend_assets(full_path: str) -> FileResponse:
    if full_path.startswith("api/"):
        raise HTTPException(status_code=404, detail="Not found")

    if not FRONTEND_DIST.exists():
        raise HTTPException(status_code=404, detail="Frontend build not found")

    safe_base = FRONTEND_DIST.resolve()
    requested = (FRONTEND_DIST / full_path).resolve()
    if not str(requested).startswith(str(safe_base)):
        raise HTTPException(status_code=404, detail="Not found")

    if requested.is_file():
        return FileResponse(path=str(requested))

    index_path = FRONTEND_DIST / "index.html"
    if not index_path.exists():
        raise HTTPException(status_code=404, detail="Frontend build not found")

    return FileResponse(path=str(index_path), media_type="text/html")


